from functools import lru_cache
class Solution:
    def minOperations(self, s1, s2, x):
        n = len(s1)
        diffs = tuple(i for i in range(n) if s1[i] != s2[i])
        k = len(diffs)
        if k % 2 == 1:
            return -1
        if k == 0:
            return 0

        @lru_cache(maxsize=None)
        def rec(remaining):
            if not remaining:
                return 0
            first = remaining[0]
            rest = remaining[1:]
            best = None
            for i in range(len(rest)):
                partner = rest[i]
                nxt = rest[:i] + rest[i + 1:]
                cost = min(x, abs(partner - first)) + rec(nxt)
                if best is None or cost < best:
                    best = cost
            return best

        result = rec(diffs)
        rec.cache_clear()
        return result

