        n = len(s1)
        diffs = [i for i in range(n) if s1[i] != s2[i]]
        k = len(diffs)
        if k % 2 == 1:
            return -1
        if k == 0:
            return 0
        INF = float('inf')
        dp0 = [INF] * (k + 1)
        dp1 = [INF] * (k + 1)
        dp0[0] = 0
        for i in range(k):
            if dp0[i] < INF:
                if dp0[i] < dp1[i + 1]:
                    dp1[i + 1] = dp0[i]
                if i + 1 < k:
                    cost = dp0[i] + min(x, diffs[i + 1] - diffs[i])
                    if cost < dp0[i + 2]:
                        dp0[i + 2] = cost
            if dp1[i] < INF:
                cost = dp1[i] + x
                if cost < dp0[i + 1]:
                    dp0[i + 1] = cost
                if i + 1 < k:
                    cost2 = dp1[i] + min(x, diffs[i + 1] - diffs[i])
                    if cost2 < dp1[i + 2]:
                        dp1[i + 2] = cost2
        return dp0[k]

