var minOperations = function(s1, s2, x) {
    const n = s1.length;
    const diffs = [];
    for (let i = 0; i < n; i++) if (s1[i] !== s2[i]) diffs.push(i);
    const k = diffs.length;
    if (k % 2 === 1) return -1;
    if (k === 0) return 0;
    const INF = Infinity;
    const dp0 = new Array(k + 1).fill(INF);
    const dp1 = new Array(k + 1).fill(INF);
    dp0[0] = 0;
    for (let i = 0; i < k; i++) {
        if (dp0[i] < INF) {
            if (dp0[i] < dp1[i + 1]) dp1[i + 1] = dp0[i];
            if (i + 1 < k) {
                const cost = dp0[i] + Math.min(x, diffs[i + 1] - diffs[i]);
                if (cost < dp0[i + 2]) dp0[i + 2] = cost;
            }
        }
        if (dp1[i] < INF) {
            const cost = dp1[i] + x;
            if (cost < dp0[i + 1]) dp0[i + 1] = cost;
            if (i + 1 < k) {
                const cost2 = dp1[i] + Math.min(x, diffs[i + 1] - diffs[i]);
                if (cost2 < dp1[i + 2]) dp1[i + 2] = cost2;
            }
        }
    }
    return dp0[k];
};
